INSERT INTO recipes (name,category_id,color,price,is_public,tags,ingredients,steps,cover_emoji) VALUES
('鱼香肉丝',1,'#ff8baa',32,1,'["午餐","晚餐","肉类"]','[{"name":"猪里脊","amount":"250g","cat":"肉类"},{"name":"干木耳","amount":"50g","cat":"蔬菜"},{"name":"胡萝卜","amount":"50g","cat":"蔬菜"},{"name":"青椒","amount":"30g","cat":"蔬菜"},{"name":"生抽","amount":"适量","cat":"调味料"}]','[{"text":"猪里脊切丝，加盐料酒淀粉腌制15分钟"},{"text":"木耳泡发切丝，胡萝卜青椒切丝备用"},{"text":"用生抽醋糖淀粉调鱼香汁"},{"text":"热油爆香蒜末，下肉丝滑炒至变色，加配菜翻炒"},{"text":"倒入鱼香汁，大火收汁出锅"}]','[肉][木耳]'),
('红烧肉',1,'#ff8baa',58,1,'["午餐","晚餐","肉类"]','[{"name":"五花肉","amount":"500g","cat":"肉类"},{"name":"冰糖","amount":"30g","cat":"调味料"},{"name":"生抽","amount":"适量","cat":"调味料"},{"name":"八角","amount":"2个","cat":"调味料"}]','[{"text":"五花肉切块，冷水下锅焯水去血沫"},{"text":"锅中放少许油，加冰糖炒出糖色"},{"text":"放入五花肉翻炒上色，加生抽八角开水没过肉"},{"text":"小火慢炖40分钟，大火收汁即可"}]','[肉][冰糖]'),
('西红柿炒鸡蛋',2,'#79bcff',18,1,'["早餐","午餐","晚餐","蔬菜"]','[{"name":"西红柿","amount":"2个","cat":"蔬菜"},{"name":"鸡蛋","amount":"3个","cat":"其他辅料"},{"name":"白糖","amount":"适量","cat":"调味料"},{"name":"盐","amount":"适量","cat":"调味料"}]','[{"text":"鸡蛋打散，西红柿切块备用"},{"text":"热油倒入蛋液，炒至定型盛出"},{"text":"锅中留底油，下西红柿炒出汤汁"},{"text":"倒入炒好的鸡蛋，加盐糖翻炒均匀"}]','[番茄][蛋]'),
('酸辣土豆丝',2,'#79bcff',16,1,'["午餐","晚餐","蔬菜"]','[{"name":"土豆","amount":"2个","cat":"蔬菜"},{"name":"干辣椒","amount":"5个","cat":"调味料"},{"name":"醋","amount":"适量","cat":"调味料"},{"name":"蒜片","amount":"适量","cat":"调味料"}]','[{"text":"土豆切细丝，用清水浸泡去淀粉"},{"text":"热油爆香干辣椒蒜片"},{"text":"下土豆丝大火快炒，加醋盐调味"},{"text":"炒至土豆丝断生即可出锅"}]','[土豆][辣椒]'),
('地三鲜',2,'#79bcff',28,1,'["午餐","晚餐","蔬菜"]','[{"name":"土豆","amount":"1个","cat":"蔬菜"},{"name":"茄子","amount":"1个","cat":"蔬菜"},{"name":"青椒","amount":"1个","cat":"蔬菜"},{"name":"生抽","amount":"适量","cat":"调味料"}]','[{"text":"土豆茄子切滚刀块，青椒切块"},{"text":"油温六成热，分别下土豆茄子炸至金黄捞出"},{"text":"锅中留底油，爆香蒜末，加生抽清水调汁"},{"text":"倒入所有食材翻炒，勾芡收汁出锅"}]','[茄子][土豆]'),
('酸辣汤',4,'#ffb37c',16,1,'["午餐","晚餐","汤类"]','[{"name":"鸡蛋","amount":"1个","cat":"其他辅料"},{"name":"豆腐","amount":"半块","cat":"豆制品"},{"name":"醋","amount":"适量","cat":"调味料"},{"name":"白胡椒粉","amount":"适量","cat":"调味料"}]','[{"text":"锅中加清水烧开，豆腐切丝放入"},{"text":"加醋、白胡椒粉、盐调味"},{"text":"鸡蛋打散缓缓倒入锅中形成蛋花"},{"text":"勾薄芡，淋香油出锅"}]','[汤][豆腐]'),
('蛋炒饭',5,'#6de192',18,1,'["早餐","午餐","面食"]','[{"name":"米饭","amount":"2碗","cat":"其他辅料"},{"name":"鸡蛋","amount":"2个","cat":"其他辅料"},{"name":"火腿肠","amount":"1根","cat":"肉类"},{"name":"葱花","amount":"适量","cat":"蔬菜"}]','[{"text":"鸡蛋打散炒熟盛出备用"},{"text":"锅中放油，放入米饭炒散"},{"text":"加入火腿肠丁、鸡蛋、盐翻炒均匀"},{"text":"撒上葱花即可出锅"}]','[饭][蛋]'),
('桂花糕',6,'#6de192',18,1,'["甜点","小吃"]','[{"name":"糯米粉","amount":"200g","cat":"其他辅料"},{"name":"桂花蜜","amount":"适量","cat":"调味料"},{"name":"白糖","amount":"20g","cat":"调味料"},{"name":"温水","amount":"适量","cat":"其他辅料"}]','[{"text":"糯米粉加白糖温水揉成面团"},{"text":"面团擀成薄饼，上锅蒸15分钟"},{"text":"蒸好后切块，淋上桂花蜜"},{"text":"撒上干桂花即可"}]','[糕][桂花]'),
('红糖糍粑',6,'#6de192',22,1,'["甜点","小吃"]','[{"name":"糯米糍粑","amount":"200g","cat":"其他辅料"},{"name":"红糖","amount":"30g","cat":"调味料"},{"name":"黄豆粉","amount":"适量","cat":"其他辅料"},{"name":"清水","amount":"适量","cat":"其他辅料"}]','[{"text":"红糖加温水化开成红糖水"},{"text":"油温六成热，下糍粑炸至金黄捞出"},{"text":"糍粑淋上红糖水"},{"text":"撒上黄豆粉即可"}]','[糍粑][红糖]');
